import React, { useState, useEffect, useContext } from 'react';
import { AuthContext } from '../context/AuthContext';
import LoadingSpinner from '../components/common/LoadingSpinner';
import MovieCard from '../components/movies/MovieCard';
import { getRecommendations, getPopularMovies } from '../services/recommendationService';
import '../styles/RecommendationsPage.css';

const RecommendationsPage = () => {
  const { user, isAuthenticated } = useContext(AuthContext);
  const [recommendations, setRecommendations] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetchRecommendations();
  }, [isAuthenticated]);

  const fetchRecommendations = async () => {
    setLoading(true);
    setError(null);

    try {
      let data;

      if (isAuthenticated) {
        // Get personalized recommendations for logged-in users
        console.log('👤 Fetching personalized recommendations...');
        data = await getRecommendations(20);

        // If no personalized recommendations, fall back to popular movies
        if (!data.recommendations || data.recommendations.length === 0) {
          console.log('📈 No personalized recommendations, falling back to popular movies...');
          const popularData = await getPopularMovies(null, 20);
          data = {
            recommendations: popularData.movies || [],
            count: popularData.count || 0
          };
        }
      } else {
        // Get popular movies for non-authenticated users
        console.log('🎬 Fetching popular movies for guest user...');
        const popularData = await getPopularMovies(null, 20);
        data = {
          recommendations: popularData.movies || [],
          count: popularData.count || 0
        };
      }

      // Ensure we always have an array, even if API fails
      setRecommendations(Array.isArray(data.recommendations) ? data.recommendations : []);

      console.log('✅ Recommendations loaded:', data.recommendations?.length || 0);
    } catch (error) {
      console.error('❌ Error fetching recommendations:', error);
      setError('Failed to load recommendations. Please try again.');
      setRecommendations([]); // Set empty array to prevent .map() errors
    } finally {
      setLoading(false);
    }
  };

  const handleRetry = () => {
    fetchRecommendations();
  };

  if (loading) {
    return <LoadingSpinner />;
  }

  return (
    <div className="recommendations-page">
      <div className="page-header">
        <h1>
          {isAuthenticated 
            ? `Recommended for ${user?.username || 'You'}` 
            : 'Popular Movies'
          }
        </h1>
        <p className="page-description">
          {isAuthenticated 
            ? 'Discover movies tailored to your taste based on your ratings and preferences.'
            : 'Check out the most popular movies loved by our community.'
          }
        </p>
      </div>

      {/* Error State */}
      {error && (
        <div className="error-container">
          <div className="error-message">
            <h3>Oops! Something went wrong</h3>
            <p>{error}</p>
            <button onClick={handleRetry} className="retry-button">
              Try Again
            </button>
          </div>
        </div>
      )}

      {/* Empty State */}
      {!error && (!recommendations || recommendations.length === 0) && (
        <div className="empty-state">
          <div className="empty-message">
            <h3>No recommendations available</h3>
            <p>
              {isAuthenticated 
                ? 'Rate some movies to get personalized recommendations!' 
                : 'Please check back later or try browsing our movie catalog.'
              }
            </p>
            {isAuthenticated && (
              <a href="/movies" className="browse-movies-button">
                Browse Movies to Rate
              </a>
            )}
          </div>
        </div>
      )}

      {/* Movies Grid */}
      {!error && recommendations && recommendations.length > 0 && (
        <div className="recommendations-content">
          <div className="movies-grid">
            {recommendations.map((movie, index) => (
              <MovieCard 
                key={movie.id || `movie-${index}`} 
                movie={movie} 
              />
            ))}
          </div>

          <div className="recommendations-footer">
            <p>
              Showing {recommendations.length} recommended movies
              {isAuthenticated && (
                <span> • <a href="/movies" className="browse-link">Browse more movies</a></span>
              )}
            </p>
          </div>
        </div>
      )}
    </div>
  );
};

export default RecommendationsPage;
